def repeat(n):
    def deco(f):
        def w(*a):
            r = None
            for _ in range(n):
                r = f(*a)
            return r
        return w
    return deco
calls = []
@repeat(3)
def rec():
    calls.append(1)
rec()
print(len(calls))
```
